 1	import React from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  DashboardsOverviewHealthSubsystem as DynamicDashboardsOverviewHealthSubsystem,
 7	  isDashboardsOverviewHealthSubsystem as isDynamicDashboardsOverviewHealthSubsystem,
 8	  isResolvedDashboardsOverviewHealthURLSubsystem,
 9	  K8sResourceCommon,
10	  useK8sWatchResource,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import { HealthBody } from '@openshift-console/dynamic-plugin-sdk-internal';
13	import { Card, CardHeader, CardTitle, Gallery, GalleryItem } from '@patternfly/react-core';
14	
15	import { VIRTUALIZATION } from './utils/constants';
16	import useDashboardSubsystems from './utils/hooks/useDashboardSubsystems';
17	import NetworkingHealthItem from './utils/NetworkingHealthItem';
18	import StorageHealthItem from './utils/storage-health-item/StorageHealthItem';
19	import { VirtStatusItems } from './utils/types';
20	import URLHealthItem from './utils/URLHealthItem';
21	import { getClusterNAC, NetworkAddonsConfigResource } from './utils/utils';
22	import VirtualizationAlerts from './utils/VirtualizationAlerts';
23	
24	const StatusCard = () => {
25	  const { t } = useKubevirtTranslation();
26	  const subsystems = useDashboardSubsystems<DynamicDashboardsOverviewHealthSubsystem>(
27	    isDynamicDashboardsOverviewHealthSubsystem,
28	  );
29	
30	  const [networkAddonsConfigList] = useK8sWatchResource<K8sResourceCommon[]>(
31	    NetworkAddonsConfigResource,
32	  );
33	  const clusterNAC = getClusterNAC(networkAddonsConfigList);
34	
35	  const virtStatusItems: VirtStatusItems = [];
36	  subsystems?.forEach((subsystem) => {
37	    if (
38	      isResolvedDashboardsOverviewHealthURLSubsystem(subsystem) &&
39	      subsystem?.properties?.title === VIRTUALIZATION
40	    ) {
41	      virtStatusItems.push({
42	        Component: <URLHealthItem subsystem={subsystem.properties} />,
43	        title: t('Virtualization'),
44	      });
45	    }
46	  });
47	
48	  virtStatusItems.push({
49	    Component: <NetworkingHealthItem nac={clusterNAC} />,
50	    title: t('Networking'),
51	  });
52	
53	  virtStatusItems.push({
54	    Component: <StorageHealthItem />,
55	    title: t('Storage'),
56	  });
57	
58	  return (
59	    <Card className="co-overview-card--gradient" data-test-id="kv-overview-status-card">
60	      <CardHeader
61	        actions={{
62	          actions: <Link to="/monitoring/alerts">{t('View alerts')}</Link>,
63	          className: 'co-overview-card__actions',
64	          hasNoOffset: false,
65	        }}
66	      >
67	        <CardTitle>{t('Status')}</CardTitle>
68	      </CardHeader>
69	      <HealthBody>
70	        <Gallery className="co-overview-status__health" hasGutter>
71	          {virtStatusItems?.map((item) => {
72	            return <GalleryItem key={item.title}>{item.Component}</GalleryItem>;
73	          })}
74	        </Gallery>
75	      </HealthBody>
76	      <VirtualizationAlerts />
77	    </Card>
78	  );
79	};
80	
81	export default StatusCard;

